using System.ComponentModel.Composition;
using System.Drawing;
using System.Reflection;
using XrmToolBox.Extensibility;
using XrmToolBox.Extensibility.Interfaces;

namespace RolePrivilegeAnalyzer
{
    /// <summary>
    /// XrmToolBox plugin entry point.
    /// This class is discovered by XrmToolBox via MEF.
    /// </summary>
    [Export(typeof(IXrmToolBoxPlugin))]
    [ExportMetadata("Name", "Role Privilege Analyzer")]
    [ExportMetadata("Description",
        "Enterprise-grade security audit tool. Analyzes user roles, privileges, " +
        "risk levels, and provides deep access control insights with heatmap visualization, " +
        "role comparison, and analytics dashboard.")]
    [ExportMetadata("Group", "Security")]
    [ExportMetadata("Author", "Moamen Ashraf Muhammed")]
    [ExportMetadata("SmallImageBase64", "")]
    [ExportMetadata("BigImageBase64", "")]
    [ExportMetadata("BackgroundColor", "#F0F8FF")]
    [ExportMetadata("PrimaryFontColor", "#1E3A8A")]
    [ExportMetadata("SecondaryFontColor", "Gray")]
    public class RolePrivilegeAnalyzerPlugin : PluginBase
    {
        public override IXrmToolBoxPluginControl GetControl()
        {
            return new UI.RolePrivilegeAnalyzerControl();
        }
    }
